const body = $input.first().json.body || $input.first().json;

return [{
  json: {
    command: body.command || '',
    question: body.question || '',
    keywords: body.keywords || '',
    room: body.room || 'qa',
    bot_type: body.bot_type || 'qa'
  }
}];

const question = $input.first().json.question || '';

if (!question) {
  throw new Error('question parameter is required');
}

return [{
  json: {
    question: question
  }
}];

const response = $input.first().json;
const question = $('准备问答请求').first().json.question;
const retrievalResponse = $('问答补充来源检索').first()?.json || {};
const inputData = $('标准化输入').first().json;
const room = inputData.room || 'qa';

const isTimeout = response.name === 'AxiosError' || (response.message && response.message.includes('timeout'));
const isRateLimit = response.message && (response.message.includes('429') || response.message.includes('rate'));
const isError = (response.error && !response.choices && !response.data) || isTimeout;

if (isError) {
  let errMsg = 'RAGFlow API 调用失败';
  if (isRateLimit) {
    errMsg = 'AI 模型繁忙（速率限制），请等待 30 秒后重试';
  } else if (isTimeout) {
    errMsg = '知识库响应超时，请稍后重试。如果持续超时，可尝试简化问题或使用 !搜 关键词';
  } else {
    errMsg = response.message || response.error || errMsg;
  }
  return [{ json: { success: false, error: errMsg, room: room } }];
}

let answer = '';
let references = [];

if (response.choices && response.choices.length > 0) {
  answer = (response.choices[0].message?.content || '').trim();
} else if (response.data) {
  const ragData = response.data?.data || response.data;
  answer = (ragData.answer || '').trim();
  references = ragData.references || ragData.reference || [];
}

if (!answer) {
  return [{ json: { success: false, error: '知识库未返回有效答案，请稍后重试或改用 !搜 关键词', room: room } }];
}

const retrievalChunks = Array.isArray(retrievalResponse.data?.chunks) ? retrievalResponse.data.chunks : [];
const normalizedFromChat = Array.isArray(references) ? references.map((ref) => ({
  docName: (ref.doc_name || ref.document_keyword || '未知文档').replace(/\.md$/, ''),
  similarity: ref.similarity ? Math.round(ref.similarity * 100) : 0,
  snippet: (ref.content || ref.chunk || '').replace(/\s+/g, ' ').trim()
})) : [];
const normalizedFromRetrieval = retrievalChunks.map((chunk) => ({
  docName: (chunk.document_keyword || chunk.doc_name || '未知文档').replace(/\.md$/, ''),
  similarity: chunk.similarity ? Math.round(chunk.similarity * 100) : 0,
  snippet: (chunk.content || '').replace(/[\[\]()#*>|!]/g, '').replace(/\s+/g, ' ').trim()
}));

const mergedReferences = [];
const seen = new Set();
for (const ref of [...normalizedFromChat, ...normalizedFromRetrieval]) {
  const key = `${ref.docName}::${ref.snippet.slice(0, 80)}`;
  if (!seen.has(key)) {
    seen.add(key);
    mergedReferences.push(ref);
  }
}

mergedReferences.sort((a, b) => (b.similarity || 0) - (a.similarity || 0));
const topReferences = mergedReferences.slice(0, 3);

let message = `📘 知识库回答\n\n问题：${question}\n\n## 核心答案\n${answer}`;

if (topReferences.length > 0) {
  message += '\n\n## 参考来源';
  topReferences.forEach((ref, index) => {
    const snippet = ref.snippet ? `\n   摘要：${ref.snippet.slice(0, 180)}${ref.snippet.length > 180 ? '...' : ''}` : '';
    const score = ref.similarity ? ` (${ref.similarity}%)` : '';
    message += `\n${index + 1}. ${ref.docName}${score}${snippet}`;
  });
}

return [{
  json: {
    success: true,
    message,
    room: room,
    data: {
      answer,
      references: topReferences,
      retrievalCount: mergedReferences.length
    }
  }
}];

const keywords = $input.first().json.keywords || '';

if (!keywords) {
  throw new Error('keywords parameter is required');
}

return [{
  json: {
    keywords: keywords
  }
}];

const response = $input.first().json;
const keywords = $('准备搜索请求').first().json.keywords;
const inputData = $('标准化输入').first().json;
const room = inputData.room || 'qa';

if (response.error || response.errcode) {
  return [{
    json: {
      success: false,
      error: response.error || response.message || 'RAGFlow 检索失败',
      room: room
    }
  }];
}

const chunks = response.data?.chunks || [];

if (chunks.length === 0) {
  return [{
    json: {
      success: true,
      message: `🔍 搜索结果: ${keywords}\n\n未找到相关内容`,
      room: room
    }
  }];
}

let message = `🔍 搜索结果: ${keywords}\n`;

chunks.forEach((chunk, i) => {
  const docName = (chunk.document_keyword || chunk.doc_name || '未知文档').replace(/\.md$/, '');
  const rawContent = (chunk.content || '').replace(/[\[\]()#*>|!]/g, '').replace(/\s+/g, ' ').trim();
  const content = rawContent.substring(0, 120);
  const similarity = chunk.similarity ? Math.round(chunk.similarity * 100) : 0;
  message += `\n${i+1}. ${docName} (${similarity}%)\n   ${content}...\n`;
});

message += `\n共找到 ${chunks.length} 条相关内容`;

return [{
  json: {
    success: true,
    message: message,
    room: room,
    data: {
      chunks: chunks
    }
  }
}];

const data = $input.first().json;
const room = data.room || 'qa';

let message = '';
let html = '';

if (data.success === false || data.error) {
  const errMsg = typeof data.error === 'object' ? (data.error.message || JSON.stringify(data.error)) : String(data.error || '未知错误');
  message = `❌ 操作失败: ${errMsg}`;
  html = `<p>❌ 操作失败: ${errMsg}</p>`;
} else if (data.message) {
  message = data.message;
  const lines = data.message.split('\n');
  const htmlParts = [];
  let inList = false;

  for (let i = 0; i < lines.length; i++) {
    let line = lines[i];

    if (!line.trim()) {
      if (inList) { htmlParts.push('</ol>'); inList = false; }
      continue;
    }

    line = line.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    line = line.replace(/\*\*(.+?)\*\*/g, '<b>$1</b>');
    line = line.replace(/`([^`]+)`/g, '<code>$1</code>');

    if (/^[📘🔍🤖]/.test(line)) {
      if (inList) { htmlParts.push('</ol>'); inList = false; }
      htmlParts.push(`<h4>${line}</h4>`);
      continue;
    }

    if (/^问题：/.test(line)) {
      if (inList) { htmlParts.push('</ol>'); inList = false; }
      htmlParts.push(`<p><em>${line}</em></p>`);
      continue;
    }

    const h2Match = line.match(/^## (.+)$/);
    if (h2Match) {
      if (inList) { htmlParts.push('</ol>'); inList = false; }
      htmlParts.push(`<h5>${h2Match[1]}</h5>`);
      continue;
    }

    const summaryMatch = line.match(/^\s+摘要：(.+)$/);
    if (summaryMatch) {
      htmlParts.push(`<blockquote>${summaryMatch[1]}</blockquote>`);
      continue;
    }

    const numMatch = line.match(/^(\d+)\.\s+(.+)$/);
    if (numMatch) {
      if (!inList) { htmlParts.push('<ol>'); inList = true; }
      htmlParts.push(`<li>${numMatch[2]}</li>`);
      continue;
    }

    const bulletMatch = line.match(/^[*\-]\s+(.+)$/);
    if (bulletMatch) {
      if (inList) { htmlParts.push('</ol>'); inList = false; }
      htmlParts.push(`<p>• ${bulletMatch[1]}</p>`);
      continue;
    }

    if (inList) { htmlParts.push('</ol>'); inList = false; }
    htmlParts.push(`<p>${line}</p>`);
  }
  if (inList) { htmlParts.push('</ol>'); }
  html = htmlParts.join('\n');
} else {
  message = '✅ 操作成功';
  html = '<p>✅ 操作成功</p>';
}

return [{ json: { room, message, html } }];

